import React, { useState, useMemo, useCallback } from 'react';
import { usePokemonChampions } from './hooks/usePokemonChampions';
import { usePokemonParty } from './hooks/usePokemonParty';
import { pokemonChampionsApi } from './services/pokemonChampionsApi';
import PokemonChampionList from './components/PokemonChampionList';
import PokemonChampionDetail from './components/PokemonChampionDetail';
import PokemonPartyPanel from './components/PokemonPartyPanel';
import InstantSearchBar from './components/InstantSearchBar';
import { PokemonWithStats } from './types/pokemonChampions';

function App() {
  const { pokemon, loading, error, refetch } = usePokemonChampions();
  const { party, addToParty, removeFromParty, swapInParty, clearParty, isInParty } = usePokemonParty();
  const [selectedPokemon, setSelectedPokemon] = useState<PokemonWithStats | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [swapSlotIndex, setSwapSlotIndex] = useState<number | null>(null);
  const [isSwapMode, setIsSwapMode] = useState(false);

  const handlePokemonSelect = useCallback((pokemon: PokemonWithStats) => {
    if (isSwapMode && swapSlotIndex !== null) {
      swapInParty(swapSlotIndex, pokemon);
      setSwapSlotIndex(null);
      setIsSwapMode(false);
    } else {
      setSelectedPokemon(pokemon);
    }
  }, [isSwapMode, swapSlotIndex, swapInParty]);

  const handleAddToParty = useCallback((pokemon: PokemonWithStats) => {
    if (!isInParty(pokemon)) {
      addToParty(pokemon);
    }
  }, [addToParty, isInParty]);

  const handleRemoveFromParty = useCallback((index: number) => {
    removeFromParty(index);
  }, [removeFromParty]);

  const handleSwapInParty = useCallback((index: number) => {
    setSwapSlotIndex(index);
    setIsSwapMode(true);
  }, []);

  const handleSwapSelect = useCallback((pokemon: PokemonWithStats) => {
    if (swapSlotIndex !== null) {
      swapInParty(swapSlotIndex, pokemon);
      setSwapSlotIndex(null);
      setIsSwapMode(false);
    }
  }, [swapSlotIndex, swapInParty]);

  const handleSearch = useCallback(async (query: string) => {
    setSearchQuery(query);
  }, []);

  const filteredPokemon = useMemo(() => {
    if (searchQuery.trim() === '') {
      return pokemon;
    }
    return pokemon.filter(p => 
      p.champion.name.toLowerCase().startsWith(searchQuery.toLowerCase()) ||
      p.champion.types.some(type => type.toLowerCase().startsWith(searchQuery.toLowerCase())) ||
      Object.values(p.champion.abilities).some(ability => 
        ability.toLowerCase().startsWith(searchQuery.toLowerCase())
      )
    );
  }, [pokemon, searchQuery]);

  const displayPokemon = useMemo(() => {
    return filteredPokemon;
  }, [filteredPokemon]);

  return (
    <div className="min-h-screen bg-gray-100">
      <div className="container mx-auto px-4 py-8">
        <PokemonPartyPanel
          party={party}
          onRemoveFromParty={handleRemoveFromParty}
          onSwapInParty={handleSwapInParty}
          isSwapMode={isSwapMode}
        />

        <header className="mb-6">
          <div className="flex flex-wrap items-center gap-4 mb-4">
            <div className="flex-1 max-w-md">
              <InstantSearchBar onSearch={handleSearch} />
            </div>
          </div>

          <div className="flex items-center gap-4 text-sm">
            <span className="text-gray-600">
              {displayPokemon.length} Pokémon Champions found
              {searchQuery && ` for "${searchQuery}"`}
            </span>
            <button
              onClick={refetch}
              className="px-4 py-2 bg-blue-500 text-white rounded-md hover:bg-blue-600 transition-colors"
            >
              Refresh Data
            </button>
            {!isSwapMode && (
              <button
                onClick={clearParty}
                className="px-4 py-2 bg-red-500 text-white rounded-md hover:bg-red-600 transition-colors"
              >
                Clear Party
              </button>
            )}
            {isSwapMode && (
              <button
                onClick={() => {
                  setSwapSlotIndex(null);
                  setIsSwapMode(false);
                }}
                className="px-4 py-2 bg-gray-500 text-white rounded-md hover:bg-gray-600 transition-colors"
              >
                Cancel Swap
              </button>
            )}
          </div>
        </header>

        <main>
          <PokemonChampionList
            pokemon={pokemon}
            filteredPokemon={displayPokemon}
            loading={loading}
            error={error}
            onPokemonSelect={handlePokemonSelect}
            onAddToParty={handleAddToParty}
            showPartyActions={true}
            isSwapMode={isSwapMode}
            onSwapSelect={handleSwapSelect}
          />
        </main>
      </div>

      <PokemonChampionDetail
        pokemon={selectedPokemon}
        onClose={() => setSelectedPokemon(null)}
      />
    </div>
  );
}

export default App;
